const Q_ECONOMICS_2007=[{"id": "objective>Economics>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The choice of what to produce in a command economy is determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial establishments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Labour unions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the government and labour unions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the central government </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a command economy, the central government makes all decisions about the production and consumption of goods and services. It determines what goods and services to produce, how to produce them, and who will receive them. This is because the government owns and controls all resources, including land, labor, and capital. Therefore, the choice of what to produce in a command economy is determined by the central government.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The logical sequence of basic concepts in economics is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wants, choice, scarcity and opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity, choice, scale of preference and opportunity cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wants, scarcity, choice and opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scarcity, wants, choice and scale of preference</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic concept of government are: Wants, scarcity, Scale of preference, choice and opportunity cost.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economic system in which the producer and the consumer are the same is referred to as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsistence economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialist economy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A subsistence economy is a non-monetary economy which relies on natural resources to provide for basic needs, through hunting, gathering, and subsistence agriculture. In this type of economy, the producer and the consumer are usually the same. The producer produces the goods and services for their own consumption.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term <em>ceteris paribus</em> implies that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all factors are fully utilized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human beings are unpredictable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">resources are scarce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human problems can be solved</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ceteris paribus is a Latin phrase meaning \"with other things being equal or held constant. Ceteris paribus is a Latin phrase that means \"all other things being equal.\" Experts use it to explain the theory behind laws of economics and nature. It means that most of the time, something will occur as a result of something else.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The range is used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">estimate the mean from grouped data</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the spread of a set of data</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calculate the standard deviation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">measure the difference between the mean and the mode</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the spread of a set of data. The range of a set of data is the difference between the highest and lowest values in the set. To find the range, first order the data from least to greatest. Then subtract the smallest value from the largest value in the set.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table below to answer this question  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Class mark (₦)</td><td style=\"border:1px solid black;text-align:center;\"> 2 </td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 8 </td><td style=\"border:1px solid black;text-align:center;\">11</td><td style=\"border:1px solid black;text-align:center;\"> 14</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Frequency</td><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr></table></div>  <br/> <strong>The table shows the wage distribution of workers.</strong> <br/>  <br/> Calculate the mean wage.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦14.80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4.00</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mean = ∑fx/∑f <br/>  <br/>  =        (2 X 2) + (3 X 5) + (1 X 8) + (3 X 11) + (1 X 14) /10 <br/>  <br/>  = (4 + 15 + 8 + 33 + 14)/10  <br/>  <br/>      = 74/10  <br/>  <br/>        = 7.40</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table below to answer this question  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Class mark (₦)</td><td style=\"border:1px solid black;text-align:center;\"> 2 </td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 8 </td><td style=\"border:1px solid black;text-align:center;\">11</td><td style=\"border:1px solid black;text-align:center;\"> 14</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Frequency</td><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr></table></div>  <br/> <strong>The table shows the wage distribution of workers.</strong> <br/> What is the median wage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦11.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦5.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">median wage : Using = f /2 since the total frequency is even <br/> Therefore, 10/2 = 5th position <br/>                 Counting(adding) the frequency from the beginning, we have the 5th position to fall in i.e 2 + 3 = 5 <br/> Therefore, median = 5 <br/>                                 </div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the demand for a good increases owing to an increase in income, it mean that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is an increase in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation has taken place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand has exceeded supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is an increase in demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increase in demand means the consumer buys more of the good at various prices than before. For example, if the income of a consumer increases, or if the fashion for a goods increases, the consumer will buy greater quantities of the goods than before at various given prices.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of cross elasticity of demand is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price of the good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of the necessity of the good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of income of consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">closeness of the substitutes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of cross-elasticity of demand is the closeness of the substitute or complement. A high positive cross-price elasticity indicates that if the price of a certain good goes up, the demand for the other good goes up as well.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A commodity is described as inferior when the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income effect is negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income effect is positive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitution effect is negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitution effect is positive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An inferior good is a good that decreases in demand when consumer income rises (or rises in demand when consumer income decreases).The income elasticity of demand coefficient (Ey) is less than 0 (negative). </div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If P = 1/2(Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + 15), what is the quantity supplied at ₦9.00?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">15)</td></tr></table></div>  <br/>  P = ₦9  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">15</td><td style=\"text-align:center;\">)</td></tr></table></div>  <br/>  18 = Qs + 15  <br/>  Qs = 18 - 15 = 3 units</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm operating at full capacity will have a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic supply curve</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Firm will have a perfectly inelastic supply curve If a firm is operating close to full capacity, then it has limited ability to increase the supply. It may be able to get workers to do some overtime, but at some point, it will meet capital limits, and it cannot increase supply without long-term capital investment.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of the price elasticity of supply is always</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">positive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Price Elasticity of Supply is always positive because the Law of Supply says that quantity supplied increases with an increase in price. This means: If the supply is elastic, producers can increase output without a rise in cost or a time delay.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world market for crude oil refers to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total supply by OPEC members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total demand for and supply of crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess crude oil produced in the world</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difference between the supply of and demand for oil</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It refers to the total demand for and supply of crude oil, it is the total quantity sold and bought.</div>", "topic": "INTERNATIONAL TRADE : OPEC, ECA, IMF"}, {"id": "objective>Economics>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The division of labour requires that the task to be performed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">must be done in stages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">requires no special knowledge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is simple but strenuous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">must be undertaken by experts</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The division of labour is a concept in economics where a large task is divided into smaller tasks, and each task is assigned to a specific worker or group of workers. These tasks are often done in stages, with each worker or group of workers specializing in a particular stage. This allows for increased efficiency and productivity. Therefore, the statement 'must be done in stages' is correct.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table below to answer this question  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">No. of workers</td><td style=\"border:1px solid black;text-align:center;\"> Output(kg) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">39 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">52 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">60 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">66 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">66 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">63</td></tr></table></div> <br/>  <br/> What is the marginal productivity when the number of workers is increased from 2 to 3?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">180kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Marginal</td><td style=\"text-align:center;\">product</td><td style=\"text-align:center;\">(MP)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔTP<hr size=\"1\" />ΔQ</td></tr></table></div>  <br/>  Where ΔTP = Change in total product  <br/>  ΔQ = Change in quantity  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">MP</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60 - 52<hr size=\"1\" />3 - 2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8kg</td></tr></table></div></div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table below to answer this question  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">No. of workers</td><td style=\"border:1px solid black;text-align:center;\"> Output(kg) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">39 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">52 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">60 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">66 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">66 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">63</td></tr></table></div> <br/> The maximum number of workers that should be hired is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of workers that should be hired is determined by the point at which the output is maximized. From the table, we can see that the output increases as the number of workers increases up to 4 workers, after which the output starts to decrease. Therefore, the maximum number of workers that should be hired is 4.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of the linear production function is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the percentage change in inputs exceed output </div>", "<div style=\"font-family:Cambria;font-size:17px;\">output and all inputs change by the same percentage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the percentage change in output is greater than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the percentage change in output is less than one </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The linear production function is the simplest form of a production function: it describes a linear relation between the input and the output. If the function has only one input, the form can be represented using the following formula:  y = a x</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the total fixed cost is the same regardless of output, the average fixed cost will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On the long run, it will decrease, an increase in output will result to decrease in average fixed cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm incurs short-run costs when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">operation is at its early stages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it cannot increase prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">some inputs cannot be varied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">operation is at its later stages</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, at least one factor of production is fixed; this means that output can be increased by adding more variable factors such as employing more workers and buying in more raw materials.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the marginal cost of production causes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an upward movement along the supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a downward movement along the supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a leftward shift of the supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rightward shift of the supply curve</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal cost is to the total cost, therefore, the portion that represent the supply curve of a firm is the marginal cost. The higher the marginal cost, the lower the supply and the lower the marginal cost,  the higher the supply.An increase in the marginal cost of production causes A left-ward shift in the supply curve would be caused by an increase in its marginal cost.</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a firm's average revenue curve is downward sloping, its price elasticity of demand will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">one </div>", "<div style=\"font-family:Cambria;font-size:17px;\">between zero and infinity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a firm's average revenue curve is downward sloping, its price elasticity of demand will be greater than one. This is because a downward sloping average revenue curve implies that the firm can sell more units only by lowering the price. This indicates that the demand for the firm's product is elastic, meaning that the percentage change in quantity demanded is greater than the percentage change in price, hence the price elasticity of demand is greater than one.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price per unit of a commodity to a buyer is the same as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average revenue of the seller </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue of the seller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">normal profit of the seller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost of the commodity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average revenue is similar to the price if a seller sells two units of the same product at the same price. However, the average revenue varies if the two products are sold at two different prices. Average revenue helps in estimating the profit of a business, as the profit is calculated by subtracting the average revenue from the average cost.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows a firm operating under conditions of monopolistic competition. The curve <strong>W</strong> represents its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average revenue</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It represents the average revenue or demand curve of the firm.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Corrections in the GNP figures for price changes require the use of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price deflator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price index</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retail price index</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer price index</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, the GDP deflator (implicit price deflator) is a measure of the level of prices of all new, domestically produced, final goods and services in an economy in a year. </div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One way of solving the problem of double counting is by computing national income using the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value-added method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output method</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problem of double counting is solved by Value added approach according to which chances of double counting are automatically eliminated.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the circular flow of income model, the outflow variables represent </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">injections</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leakages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the circular flow of income model, the outflow variables represent leakages. Leakages are the non-consumption uses of income, including savings, taxes, and imports. These are considered outflows because they are income that is taken out of the circular flow, reducing the total income that is available for expenditure.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of electronic banking is that it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enables a customer to operate his account from different locations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enables many customers to operate joint accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enables a customer to operate joint accounts from different locations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces risk of bank fraud </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main advantage of electronic banking is convenience. You can communicate with the bank via an online website and/or smartphone app from any location that offers an internet connection. The electronic facilities are available 24/7 and don't require you to travel to a branch.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A reduction in the bank rate encourages commercial banks to create money by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raising the interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintaining the interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doubling the interest rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It also helps them decrease the interest rate.reduction in bank rate will increase the lending power of commercial banks.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Life insurance companies contribute to economic development by holding a part of their assets in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash and near money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">money-market instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-term financial instruments</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insurance is one of the institution in capital market. Capital market is a market where long-term loans can be obtained.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The non-bank financial institutions that are entrusted with workers' contributions towards retirement are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">investment companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pension funds custodians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pension funds administrators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortgage institutions</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Pension Fund Administrator (PFA) is a company licensed by the National Pension Commission to manage and invest the pension funds in the employee's Retirement Savings Account (RSA).</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A persistent rise in the prices of inputs will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hyperinflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand-pull inflation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will lead to cost-push inflation when there is a rise in input prices, there will be an increase in cost of production which results to a decline in profit margin and the supply of good.  Cost push inflation is inflation caused by an increase in prices of inputs or factor costs like labour, raw material,etc.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The monetization policy is an offshoot of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NEEDS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SAP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PAYE</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MDGs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NEEDS was a comprehensive economic development strategy that was implemented in Nigeria from 2004 to 2007. It was designed to achieve sustainable economic growth and development, reduce poverty, and improve the standard of living for all Nigerians. <br/>  <br/> Monetization policy was one of the key components of NEEDS. It was designed to reduce the government's reliance on oil revenue and to promote private sector investment. <br/>  <br/> Under the monetization policy, the government privatized a number of public enterprises and sold off some of its assets. It also reduced the size of the civil service and implemented a number of other measures to reduce government spending.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A continuous increase in national income accompanied by the structural transformation of all indices is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic reforms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic development</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development also refers to the process by which the overall health, well-being, and academic level the general population improves. </div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a developing economy, productivity is measured by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital-output ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output per capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output-labour ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output growth rate </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a developing economy, productivity is often measured by the output-labour ratio. This ratio indicates the amount of goods and services produced per unit of labour. It is a key indicator of labour productivity and can provide insights into the efficiency of a country's workforce.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gains from international trade are shared on the basis of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity produced of each of the traded goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of production of each of the traded goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terms of trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bilateral trade of agreements</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gains from international trade are shared on the basis of the terms of trade. The terms of trade refer to the relative price of exports in terms of imports and are defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways of correcting a deficit balance of payments is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revalue a country's currency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">devalue a country's currency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce exports</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is solved by devaluing a country's currency.devalue the currency of a country when compare with other nations.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of WTO is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">help countries with chronic balance of payments problems </div>", "<div style=\"font-family:Cambria;font-size:17px;\">help debtor nations solve their problems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure adequate tariff protection for infant industries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide a mechanism for tariff reductions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It aims to cut living costs and raise living standards by providing a mechanism for tariff reductions.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum number of shareholders for a joint stock company is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum number of shareholders for a joint stock company is two. A joint stock company is a company whose stock is owned jointly by a large number of shareholders who are able to transfer their shares to others without the consent of the other shareholders. The minimum number of shareholders required to form a joint stock company is two.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The survival of a partnership depends on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the managerial ability of the partners </div>", "<div style=\"font-family:Cambria;font-size:17px;\">access to finance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the goodwill of the partners </div>", "<div style=\"font-family:Cambria;font-size:17px;\">political stability</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The survival of a partnership largely depends on the goodwill of the partners. Goodwill in this context refers to the mutual trust, cooperation, and shared vision among the partners. While managerial ability and access to finance are important, they are not the primary determinant of a partnership's survival. Political stability is also important but not the main factor. Therefore, the correct answer is 'the goodwill of the partners'.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major objective of the Federal Government's initiative on cassava production in Nigeria is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diversify the export base of the economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the availability of cassava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make cassava a staple food in the country </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide raw materials for industries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the Federal Government inaugurated the Presidential Initiative on Cassava with the objective of promoting cassava as a foreign exchange earner for the country and towards achieving self-sufficiency in food production.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country would develop its agricultural sector first so as to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stabilize the prices of agricultural products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilize the prices of industrial products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create a market for the agricultural sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create a market for the industrial sector</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural sector belongs to the primary sector, so developing it will create a market for the industrial sector.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental degradation is more associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">localization of industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">location of industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased urbanization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urban-rural migration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental degradation and pollution is a potential hazard of localization of industries due to the collective waste of such industries.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign investment can be attracted to Nigeria through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a review of the tax policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a review of interest rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the revaluation of the naira</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a review of the naturalization policy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign investment can be attracted to a country through various means. One of the most effective ways is through a review of the tax policy. A favorable tax policy can attract foreign investors as it reduces the cost of doing business and increases the potential for higher returns on investment. This is more effective than a review of interest rates, the revaluation of the naira, or a review of the naturalization policy. Therefore, the correct answer is 'a review of the tax policy'.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization is a prerequisite for balanced economic growth because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encourages trade liberalization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulates the development of all sectors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhances productivity in the manufacturing sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expands employment opportunities in urban areas</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of Industrialization is considered at the core of economic growth in any economy and it is critical for development and progress. Since the Industrial Revolution, secondary sector development is regarded important for mass production, provision of employment opportunities, gaining advantage of technological advancements.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Upstream oil activities involve the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exploration of crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining of crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing of finished products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management of pollution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are operations stages in the oil and gas industry that involve exploration and production. Upstream operations deal primarily with the exploration stages of the oil and gas industry, with upstream firms taking the first steps to first locate, test and drill for oil and gas. Later, once reserves are proven, upstream firms will extract any oil and gas from the reserve.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Malthusian theory of population has been rendered ineffective by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government policies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural disasters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birth control measures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical progress</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He wrote that population growth occurs exponentially, so it increases according to birth rate. For example, if every member of a family tree reproduces, the tree will continue to grow with each generation. On the other hand, food production increases arithmetically, so it only increases at given points in time. Malthus wrote that, left unchecked, populations can outgrow their resources. </div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of people from rural to urban areas affects the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">occupational distribution of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex distribution of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geographical distribution of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">age  distribution of population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of people from rural to urban areas affects the geographical distribution of population. This is because when people move from one place to another, they change the population distribution of those areas. In this case, the rural areas will have a decrease in population while the urban areas will have an increase in population.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An upward review of the retirement age will affect the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand for labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wage rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will affect supply of labour,it will increase labour supply and create unemployment in the economy.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force of a country best describes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the number of people in paid employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the number of people receiving pension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people within the retirement age </div>", "<div style=\"font-family:Cambria;font-size:17px;\">people within the working age </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour force or working population or active population is the total number of people within the working age and who are able and willing to work.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}];
